//  POWER METER
// ═══════════════════════════════════════════════════════
let powerIv=null;
function startPower(){
  S.power=0;S.powerDir=1;
  document.getElementById("power-wrap").style.display="block";
  powerIv=setInterval(()=>{
    S.power+=S.powerDir*3;
    if(S.power>=100){S.power=100;S.powerDir=-1;}
    if(S.power<=0)  {S.power=0;  S.powerDir= 1;}
    document.getElementById("power-bar").style.width=S.power+"%";
  },30);
}
function stopPower(){ clearInterval(powerIv); document.getElementById("power-wrap").style.display="none"; }

// ═══════════════════════════════════════════════════════
//  HELPERS
// ═══════════════════════════════════════════════════════
function ripple(x,y){ for(let i=0;i<4;i++) S.ripples.push({x,y:y+4,r:3+i*4,alpha:.6}); }
function coinDisplay(){
  const v = S.coins;
  document.getElementById("coin-count").textContent = v;
  const m = document.getElementById("m-coin-count");
  if(m) m.textContent = v;
}

function updateStatsDisplay(){
  const stats=computeStats();
  const isEmpty = stats.luck===0&&stats.control===0&&stats.strength===0;
  const html = isEmpty ? "" :
    (stats.luck     ?`<span class="stat-luck">🍀 ${stats.luck}</span>`:"") +
    (stats.control  ?`<span class="stat-control">🎛️ ${stats.control}</span>`:"") +
    (stats.strength ?`<span class="stat-strength">💪 ${stats.strength}</span>`:"");
  // Desktop
  const el = document.getElementById("stats-display");
  el.innerHTML = html;
  isEmpty ? el.classList.remove("has-stats") : el.classList.add("has-stats");
  // Mobile mirror
  const mel = document.getElementById("m-stats-display");
  if(mel){ mel.innerHTML = html; isEmpty ? mel.classList.remove("has-stats") : mel.classList.add("has-stats"); }
}

function updateBaitDisplay(){
  const none = equipped.bait==="none";
  const html = none ? "" : (()=>{
    const bait=BAIT_DB.find(b=>b.id===equipped.bait);
    const qty=S.baitInv[equipped.bait]||0;
    return `${bait.icon} <span style="opacity:0.8;font-weight:700">${bait.hint}</span> <span style="opacity:0.6;font-size:11px">(×${qty})</span>`;
  })();
  // Desktop
  const el=document.getElementById("bait-display");
  el.style.display = none ? "none" : "block";
  if(!none) el.innerHTML = html;
  // Mobile mirror
  const mel=document.getElementById("m-bait-display");
  if(mel){ mel.style.display = none ? "none" : "block"; if(!none) mel.innerHTML = html; }
}

let stTm=null;
function showStatus(msg,dur){
  const el=document.getElementById("status-msg");
  el.textContent=msg; el.classList.add("show");
  clearTimeout(stTm);
  if(dur>0) stTm=setTimeout(()=>el.classList.remove("show"),dur);
}
function hideStatus(){ document.getElementById("status-msg").classList.remove("show"); }

// ═══════════════════════════════════════════════════════
//  FISH GENERATOR
// ═══════════════════════════════════════════════════════
function makeFish(){
  const stats = computeStats();
  const bait  = BAIT_DB.find(b=>b.id===equipped.bait);

  // Build weighted pool with bait and luck modifiers
  let pool = FISH_DB.map(f => {
    let w = f.rarity;
    if(bait) w *= (bait.weights[f.id] ?? 1.0);
    if(stats.luck > 0){
      if(f.id==="carp") w *= 1 + stats.luck*0.08;
      if(f.id==="koi")  w *= 1 + stats.luck*0.12;
    }
    return {f, w:Math.max(0,w)};
  });

  const total = pool.reduce((s,{w})=>s+w, 0);
  const roll  = Math.random() * total;
  let cum=0;
  for(const {f,w} of pool){
    cum+=w;
    if(roll<=cum){
      const wt = +(f.weightMin+Math.random()*(f.weightMax-f.weightMin)).toFixed(2);
      const v  = Math.round(f.value*(0.8+wt/f.weightMax*0.4));
      const shiny = Math.random()<CONFIG.shinyChance;
      return {...f, weight:wt, value:shiny?Math.round(v*2.5):v, baseValue:v, shiny};
    }
  }
  return {...FISH_DB[0],weight:.2,value:4,baseValue:4,shiny:false};
}

// ═══════════════════════════════════════════════════════
//  BITE FEEDBACK
// ═══════════════════════════════════════════════════════
function biteFeedback(){
  playBite();
  const a=document.getElementById("bite-alert");
  a.classList.add("show"); setTimeout(()=>a.classList.remove("show"),CONFIG.biteAlertMs);
  const p=document.getElementById("screen-pulse");
  p.classList.add("flash"); setTimeout(()=>p.classList.remove("flash"),CONFIG.screenPulseMs);
  spawn(S.bobberX,S.bobberY,"#a8d8f0",7);
  for(let i=0;i<5;i++) ripple(S.bobberX,S.bobberY+4);
}

// ═══════════════════════════════════════════════════════
//  STATE MACHINE
// ═══════════════════════════════════════════════════════
const castBtn=document.getElementById("cast-btn");
const reelBtn=document.getElementById("reel-btn");

function startCast(){
  if(S.phase!=="idle")return;
  S.phase="charging";
  castBtn.textContent="📍 RELEASE!";
  castBtn.classList.replace("btn-green","btn-orange");
  startPower();
}
function releaseCast(){
  if(S.phase!=="charging")return;
  stopPower(); S.phase="waiting";
  castBtn.style.display="none";
  S.bobberX=W*.5+(S.power/100)*W*.3;
  S.bobberY=H*.52+Math.random()*30;
  S.bobberDip=0;
  playPlop(); ripple(S.bobberX,S.bobberY); spawn(S.bobberX,S.bobberY,"#a8d8f0",5);
  showStatus("🎣 Waiting for a bite…",1800);
  const delay=CONFIG.biteDelayMin+Math.random()*(CONFIG.biteDelayMax-CONFIG.biteDelayMin);
  S.biteTimer=setTimeout(triggerBite,delay);
  castBtn.textContent="🎣 CAST";
  castBtn.classList.replace("btn-orange","btn-green");
}
function triggerBite(){
  if(S.phase!=="waiting")return;
  S.phase="hooking"; S.activeFish=makeFish();
  biteFeedback(); hideStatus();
  castBtn.style.display="block";
  castBtn.textContent="🪝 HOOK!";
  castBtn.classList.replace("btn-green","btn-orange");
  S.hookTimeout=setTimeout(()=>{
    if(S.phase==="hooking") escape("That was a strong one… 🌊");
  },CONFIG.hookWindowMs);
}
function hookFish(){
  if(S.phase!=="hooking")return;
  clearTimeout(S.hookTimeout);
  S.phase="reeling"; S.tension=50; S.reelProgress=0; S.tickFrame=0; S.legendaryTimer=0;
  castBtn.style.display="none";
  reelBtn.style.display="block";
  document.getElementById("reel-panel").style.display="block";
  const label=S.activeFish.shiny?"✨ "+S.activeFish.name:S.activeFish.name;
  document.getElementById("fish-caught-name").textContent=S.activeFish.emoji+" "+label+" on the line!";
  hideStatus();
  startReel();
}

// ═══════════════════════════════════════════════════════
//  REEL MECHANICS — hold-to-reel, click spam has no effect
// ═══════════════════════════════════════════════════════
let reelIv=null;
let lastReelTick=0;

function startReel(){
  const fish=S.activeFish;
  S.reelHoldMs=0;
  lastReelTick=performance.now();

  reelIv=setInterval(()=>{
    if(S.phase!=="reeling"){clearInterval(reelIv);return;}

    // Track how long reel has been continuously held
    const now=performance.now();
    const dt=now-lastReelTick;
    lastReelTick=now;

    if(S.isReeling){
      S.reelHoldMs+=dt;
    } else {
      // Release resets hold timer — must re-establish hold
      S.reelHoldMs=0;
    }

    // Progress only counts after minimum continuous hold (prevents click spam)
    const holdReady = S.reelHoldMs >= S.reelHoldRequired;
    const activeReel = S.isReeling;

    if(activeReel){
      // Tension accelerates the higher it already is — holding in the red is dangerous
      const dangerMult = S.tension > CONFIG.safeZoneHigh
        ? 1.0 + (S.tension - CONFIG.safeZoneHigh) / 25  // 1x at 65%, 2x at 90%
        : 1.0;
      S.tension += CONFIG.tensionBuildRate * (1 + fish.difficulty * 0.5) * dangerMult;

      if(holdReady){
        // Progress slows sharply in the red — reward staying in the safe zone
        const progressMult = S.tension > CONFIG.safeZoneHigh ? 0.35 : 1.0;
        S.reelProgress += CONFIG.reelProgressPerFrame * (1 - fish.difficulty * 0.25) * progressMult;
      } else {
        S.reelProgress += CONFIG.reelProgressPerFrame * 0.1;
      }
    } else {
      // Bait tension bonus: matching bait gives slightly faster decay for that fish
      const bait=BAIT_DB.find(b=>b.id===equipped.bait);
      const baitBonus=(bait&&bait.tensionBonus&&bait.tensionBonus[fish.id])||0;
      // Decay is slower in red zone — can't instantly recover from danger
      const decayMult = S.tension > CONFIG.safeZoneHigh ? 0.55 : 1.0;
      S.tension      -= (CONFIG.tensionDecayRate + baitBonus) * decayMult;
      S.reelProgress -= 0.25 * fish.difficulty;
    }

    if(fish.legendary){ S.legendaryTimer++; if(S.legendaryTimer%80===0) S.tension+=20+Math.random()*8; }
    else if(Math.random()<fish.spikeChance) S.tension+=fish.spikeMin+Math.random()*(fish.spikeMax-fish.spikeMin);

    S.tension=Math.max(0,Math.min(100,S.tension));
    S.reelProgress=Math.max(0,Math.min(100,S.reelProgress));

    const fill=document.getElementById("tension-fill");
    const bgEl=document.getElementById("tension-bg");
    const inSafe=S.tension>=CONFIG.safeZoneLow&&S.tension<=CONFIG.safeZoneHigh;
    const inRed =S.tension>75;
    fill.style.width=S.tension+"%";
    fill.style.background=S.tension>75?"#e05c5c":S.tension>CONFIG.safeZoneHigh?"#f5c842":S.tension<CONFIG.safeZoneLow?"#f5c842":"#5cb85c";

    bgEl.classList.toggle("glow-good", inSafe&&holdReady);
    bgEl.classList.toggle("danger-shake", inRed&&activeReel);

    // Tick sound + particles only on sustained hold in safe zone
    if(activeReel&&inSafe&&holdReady){
      S.tickFrame++;
      if(S.tickFrame%CONFIG.tickInterval===0){
        playTick();
        spawn(S.bobberX+(Math.random()-.5)*18,S.bobberY-4,"#a8d8f0",2);
      }
    } else {
      S.tickFrame=0;
    }

    // Update hint text to guide player
    const hint=document.getElementById("reel-hint");
    if(!activeReel)          hint.textContent="Hold REEL — stay in the green zone!";
    else if(!holdReady)      hint.textContent="Keep holding…";
    else if(!inSafe&&S.tension>CONFIG.safeZoneHigh) hint.textContent="⚠️ Too much tension — ease off!";
    else if(!inSafe&&S.tension<CONFIG.safeZoneLow)  hint.textContent="Hold to reel in!";
    else                     hint.textContent="✅ Perfect — keep holding!";

    if(S.tension>=CONFIG.tensionBreakThreshold){ clearInterval(reelIv); escape("Line snapped… so close! 💔"); }
    else if(S.tension<=CONFIG.tensionEscapeThreshold&&!activeReel){ clearInterval(reelIv); escape("It swam away… nice fight! 🌊"); }
    else if(S.reelProgress>=100){ clearInterval(reelIv); catchFish(); }
  },50);
}

// ═══════════════════════════════════════════════════════
//  CATCH
// ═══════════════════════════════════════════════════════
function catchFish(){
  S.phase="caught";
  const fish=S.activeFish;
  castBtn.style.display="none"; reelBtn.style.display="none";
  document.getElementById("reel-panel").style.display="none";

  // Consume one bait
  if(equipped.bait!=="none" && S.baitInv[equipped.bait]>0){
    S.baitInv[equipped.bait]--;
    if(S.baitInv[equipped.bait]<=0){
      delete S.baitInv[equipped.bait];
      equipped.bait="none";
      showStatus("🪱 Bait used up!",1500);
    }
    updateBaitDisplay();
  }

  const isNew=!S.discovered.has(fish.id);
  if(isNew) S.discovered.add(fish.id);

  // Journal update — track count, largest, shiny
  if(!S.journal[fish.id]) S.journal[fish.id]={ count:0, largest:0, shinyCount:0 };
  S.journal[fish.id].count++;
  const isPB = fish.weight > S.journal[fish.id].largest;
  if(isPB) S.journal[fish.id].largest = fish.weight;
  if(fish.shiny) S.journal[fish.id].shinyCount++;

  // Sounds
  if(fish.shiny){ playShiny(); setTimeout(playSuccess,200); }
  else if(isNew){ playDiscovery(); }
  else { playSuccess(); }

  // Particles + catch splash
  spawn(S.bobberX, S.bobberY, fish.shiny?"#f5c842":fish.color, fish.shiny?18:12);
  // Extra water splash burst at catch
  for(let i=0;i<5;i++) ripple(S.bobberX + (Math.random()-0.5)*30, S.bobberY + Math.random()*15);
  spawn(S.bobberX, S.bobberY-10, "#a8d8f0", 6);

  // Badges
  document.getElementById("shiny-badge").style.display=fish.shiny?"block":"none";
  document.getElementById("new-badge").style.display=isNew?"block":"none";

  // Fish image in popup
  const popImg = document.getElementById("popup-emoji");
  const fishImg = FISH_IMGS[fish.id];
  if(fishImg && fishImg.complete){
    popImg.innerHTML = '';
    const el = document.createElement('img');
    el.src = fishImg.src;
    el.style.cssText = 'width:90px;height:auto;display:block;margin:0 auto;' + (fish.shiny?'filter:drop-shadow(0 0 8px #f5c842);':'');
    if(fish.shiny){ const badge=document.createElement('div'); badge.textContent='✨'; badge.style.cssText='font-size:28px;margin-top:-8px;'; popImg.appendChild(el); popImg.appendChild(badge); }
    else popImg.appendChild(el);
  } else {
    popImg.textContent = fish.emoji + (fish.shiny?" ✨":"");
  }
  document.getElementById("popup-name").textContent=fish.name+(fish.shiny?" (Shiny!)":"");
  document.getElementById("popup-sub").textContent=`${fish.weight} kg${isPB&&!isNew?" 🏆 Personal Best!":fish.shiny?"  ·  Rare find!":""}`;
  document.getElementById("popup-worth").textContent=`Sell value: ${fish.value} 🪙`;

  // Discovery banner (takes priority over PB)
  if(isNew){
    const db=document.getElementById("discovery-banner");
    db.textContent=`🔍 New Species: ${fish.name}!`;
    db.classList.add("show");
    setTimeout(()=>db.classList.remove("show"),3000);
  } else if(isPB && !fish.shiny){
    // Personal best banner — shown slightly lower so it doesn't clash
    const bb=document.getElementById("bigcatch-banner");
    bb.textContent=`🏆 Personal Best! ${fish.weight}kg`;
    bb.classList.add("show");
    setTimeout(()=>bb.classList.remove("show"),2500);
    // Extra particles for the achievement
    spawn(S.bobberX,S.bobberY,"#f5c842",10);
  }

  document.getElementById("catch-popup").classList.add("active");
  ripple(S.bobberX,S.bobberY);
}

function sellFish(){
  const fish=S.activeFish;
  S.coins+=fish.value; coinDisplay();
  document.getElementById("catch-popup").classList.remove("active");
  renderInv(); renderJournal();
  checkGoals();
  saveGame();
  resetIdle("💰 Sold for "+fish.value+" coins! Cast again?");
}

function keepFish(){
  S.bagKept.push(S.activeFish);
  document.getElementById("catch-popup").classList.remove("active");
  renderInv(); renderJournal();
  checkGoals();
  saveGame();
  resetIdle("🏠 Kept! "+S.activeFish.name+" is yours. Cast again?");
}

function escape(msg){
  playEscape();
  if(CONFIG.consolationCoins>0){ S.coins+=CONFIG.consolationCoins; coinDisplay(); }
  S.phase="idle";
  reelBtn.style.display="none";
  document.getElementById("reel-panel").style.display="none";
  document.getElementById("tension-bg").classList.remove("glow-good");
  clearTimeout(S.biteTimer);
  showStatus(msg,2600);
  setTimeout(()=>{ castBtn.textContent="🎣 CAST"; castBtn.classList.replace("btn-orange","btn-green"); castBtn.style.display="block"; S.phase="idle"; },500);
}

function resetIdle(msg){
  S.phase="idle"; S.activeFish=null;
  S.bobberX=0; S.bobberY=0; S.bobberDip=0;
  castBtn.textContent="🎣 CAST";
  castBtn.classList.replace("btn-orange","btn-green");
  castBtn.style.display="block";
  showStatus(msg,2400);
}

// ═══════════════════════════════════════════════════════
//  INVENTORY — movable fish between tabs
// ═══════════════════════════════════════════════════════
function invTab(tab){
  S.invTab=tab;
  document.querySelectorAll("#inv-tabs .tab").forEach((t,i)=>{
    t.classList.toggle("active",(i===0&&tab==="sell")||(i===1&&tab==="kept"));
  });
  renderInv();
}

function renderInv(){
  const list   = document.getElementById("inv-list");
  const footer = document.getElementById("inv-footer");
  const arr    = S.invTab==="sell" ? S.bagSell : S.bagKept;
  list.innerHTML=""; footer.innerHTML="";

  if(!arr.length){
    list.innerHTML=`<li style="color:#aaa;font-size:13px;padding:6px 0">${S.invTab==="sell"?"Nothing to sell yet — go catch some fish!":"No fish kept yet… catch one and choose 'Keep'!"}</li>`;
    document.getElementById("inv-total").textContent="";
    return;
  }

  let tot=0;
  arr.forEach((f,idx)=>{
    tot+=f.value;
    const li=document.createElement("li");
    const shinyTag=f.shiny?` <span style="color:#d4a017;font-size:11px">✨Shiny</span>`:"";
    const moveLabel = S.invTab==="sell" ? "🏠 Keep" : "🏪 Sell?";
    const moveCls   = S.invTab==="sell" ? "btn-move" : "btn-move-back";

    li.innerHTML=`
      <div class="fish-row">
        <span class="fish-label">${f.emoji} ${f.name}${shinyTag}</span>
        <span class="fish-val">${f.value} 🪙</span>
      </div>
      <div class="fish-meta">${f.weight} kg</div>
      <div class="fish-actions">
        ${S.invTab==="sell"
          ? `<button class="btn-sell-one" onclick="sellOne(${idx})">💰 Sell</button>`
          : ""}
        <button class="${moveCls}" onclick="moveFish(${idx})">${moveLabel}</button>
      </div>`;
    list.appendChild(li);
  });

  document.getElementById("inv-total").textContent=
    S.invTab==="sell"
      ? `${arr.length} fish · ${tot} 🪙 total value`
      : `${arr.length} fish in your collection`;

  // Footer buttons
  if(S.invTab==="sell" && arr.length>0){
    footer.innerHTML=`
      <button class="btn btn-coin" onclick="sellAll()" style="flex:1;padding:7px 0;font-size:12px">💰 Sell All (${tot} 🪙)</button>
      <button class="btn btn-move" onclick="moveAll()" style="flex:1;padding:7px 0;font-size:12px">🏠 Keep All</button>`;
  } else if(S.invTab==="kept" && arr.length>0){
    footer.innerHTML=`
      <button class="btn btn-move-back" onclick="moveAll()" style="flex:1;padding:7px 0;font-size:12px">🏪 Move All to Sale</button>`;
  }
}

function sellOne(idx){
  const fish=S.bagSell.splice(idx,1)[0];
  S.coins+=fish.value; coinDisplay();
  flashInvItem(); renderInv();
  saveGame();
  showStatus(`💰 Sold ${fish.name} for ${fish.value} 🪙`,1500);
}

function sellAll(){
  if(!S.bagSell.length)return;
  const tot=S.bagSell.reduce((s,f)=>s+f.value,0);
  S.coins+=tot; S.bagSell=[]; coinDisplay(); renderInv();
  saveGame();
  showStatus(`💰 Sold everything! +${tot} 🪙`,2000);
}

function moveFish(idx){
  const src = S.invTab==="sell" ? S.bagSell : S.bagKept;
  const dst = S.invTab==="sell" ? S.bagKept : S.bagSell;
  const fish=src.splice(idx,1)[0];
  dst.push(fish);
  flashInvItem(); renderInv();
  saveGame();
  const msg=S.invTab==="sell"
    ? `🏠 ${fish.name} moved to Kept`
    : `🏪 ${fish.name} moved to For Sale`;
  showStatus(msg,1400);
}

function moveAll(){
  const src = S.invTab==="sell" ? S.bagSell : S.bagKept;
  const dst = S.invTab==="sell" ? S.bagKept : S.bagSell;
  while(src.length) dst.push(src.pop());
  renderInv();
  saveGame();
  showStatus(S.invTab==="sell"?"🏠 All moved to Kept":"🏪 All moved to For Sale",1500);
}

function flashInvItem(){
  // Quick panel flash for feedback
  const panel=document.getElementById("inv-panel");
  panel.style.transition="box-shadow .15s";
  panel.style.boxShadow="0 0 18px 4px rgba(92,184,92,0.55)";
  setTimeout(()=>{ panel.style.boxShadow=""; },320);
}

// ═══════════════════════════════════════════════════════
//  JOURNAL
// ═══════════════════════════════════════════════════════
function renderJournal(){
  const list=document.getElementById("journal-list");
  list.innerHTML="";

  // Update the single summary line in the panel header (not injected repeatedly)
  const total=FISH_DB.length;
  const found=FISH_DB.filter(f=>S.discovered.has(f.id)).length;
  let summaryEl=document.getElementById("journal-summary");
  if(!summaryEl){
    summaryEl=document.createElement("div");
    summaryEl.id="journal-summary";
    summaryEl.style.cssText="font-size:12px;font-weight:700;color:#888;margin-bottom:8px";
    list.parentNode.insertBefore(summaryEl, list);
  }
  summaryEl.textContent=`${found}/${total} species discovered`;

  FISH_DB.forEach(f=>{
    const j=S.journal[f.id];
    const isFound=S.discovered.has(f.id);
    const li=document.createElement("li");

    const img=FISH_IMGS[f.id];
    const imgSrc=img&&img.complete?img.src:"";
    const imgClass=isFound?"jrnl-img":"jrnl-img undiscovered";
    const imgEl=imgSrc
      ?`<img src="${imgSrc}" class="${imgClass}" alt="${f.name}">`
      :`<div class="jrnl-img" style="background:rgba(0,0,0,0.08);border-radius:4px"></div>`;

    const pbBadge   = j&&j.largest>0 ?`<span class="jrnl-pb">🏆 ${j.largest}kg</span>`:"";
    const shinyBadge= j&&j.shinyCount>0?`<span class="jrnl-badge">✨×${j.shinyCount}</span>`:"";
    const rareBadge = f.rare?`<span style="font-size:9px;background:#e8d5f8;color:#7b4fa0;border-radius:8px;padding:1px 5px;font-weight:800;margin-left:3px">RARE</span>`:"";

    if(isFound && j){
      li.style.cssText=f.rare?"background:rgba(155,89,182,0.05);border-radius:8px;padding:4px 6px;":"";
      li.innerHTML=`<div class="jrnl-row">
        ${imgEl}
        <div class="jrnl-info">
          <div class="jrnl-name">${f.name}${rareBadge}${shinyBadge}</div>
          <div class="jrnl-record">Caught: ${j.count} ${pbBadge}</div>
        </div>
      </div>`;
    } else {
      li.innerHTML=`<div class="jrnl-row">
        ${imgEl}
        <div class="jrnl-info">
          <div class="jrnl-name" style="color:#bbb">???${f.rare?` ${rareBadge}`:""}</div>
          <div class="jrnl-record" style="color:#ccc">Not yet discovered</div>
        </div>
      </div>`;
    }
    list.appendChild(li);
  });
}

// ═══════════════════════════════════════════════════════
//  GOALS
// ═══════════════════════════════════════════════════════
let goalToastTimer=null;

function showGoalToast(msg){
  const el=document.getElementById("goal-toast");
  el.textContent=msg; el.classList.add("show");
  clearTimeout(goalToastTimer);
  goalToastTimer=setTimeout(()=>el.classList.remove("show"),3500);
}

function checkGoals(){
  let anyNew=false;
  GOALS_DB.forEach(goal=>{
    if(S.completedGoals.has(goal.id)) return;
    if(goal.check()){
      S.completedGoals.add(goal.id);
      S.coins+=goal.reward;
      coinDisplay();
      anyNew=true;
      // Stagger toasts if multiple complete at once
      setTimeout(()=>{
        showGoalToast(`🎯 Goal: ${goal.label}! +${goal.reward} 🪙`);
        spawn(W/2, H/2, "#f5c842", 12);
      }, anyNew?300:0);
    }
  });
  if(anyNew) saveGame();
}

function renderGoals(){
  const list=document.getElementById("goals-list");
  const summary=document.getElementById("goals-summary");
  list.innerHTML="";

  const done=GOALS_DB.filter(g=>S.completedGoals.has(g.id)).length;
  summary.textContent=`${done}/${GOALS_DB.length} goals completed`;

  GOALS_DB.forEach(goal=>{
    const isDone=S.completedGoals.has(goal.id);
    const div=document.createElement("div");
    div.className="goal-item"+(isDone?" done":"");
    div.innerHTML=`
      <div class="goal-check">${isDone?"✅":"⭕"}</div>
      <div class="goal-info">
        <div class="goal-label">${goal.label}</div>
        <div class="goal-desc">${goal.desc}</div>
        ${!isDone?`<div class="goal-reward">Reward: ${goal.reward} 🪙</div>`:""}
      </div>`;
    list.appendChild(div);
  });
}

