function renderShop(){
  const c=document.getElementById("shop-content");
  c.innerHTML="";

  // Rods for sale
  const rodSection=document.createElement("div");
  rodSection.className="shop-section";
  rodSection.innerHTML="<h3>🎣 RODS</h3>";
  ROD_DB.forEach(rod=>{
    if(rod.price===0) return; // basic rod is free/default
    const owned=S.ownedRods.includes(rod.id);
    const isEq=equipped.rod===rod.id;
    const div=document.createElement("div"); div.className="upgrade-item";
    const strengthStars="💪".repeat(rod.level);
    div.innerHTML=`<h4 style="color:${rod.color}">● ${rod.name} ${strengthStars}</h4>
      <p style="font-size:11px;color:#888">${rod.desc}</p>`+
      (owned
        ? `<span class="owned-badge">${isEq?"✅ Equipped":"✔ Owned — equip in Gear"}</span>`
        : `<div class="cost-line">${rod.price} 🪙</div>
           <button class="btn btn-coin upg-btn" onclick="buyRod('${rod.id}')">Buy</button>`);
    rodSection.appendChild(div);
  });
  c.appendChild(rodSection);

  // Reels for sale
  const reelSection=document.createElement("div");
  reelSection.className="shop-section";
  reelSection.innerHTML="<h3>🌀 REELS</h3>";
  REEL_DB.forEach(reel=>{
    if(reel.price===0) return;
    const owned=S.ownedReels.includes(reel.id);
    const isEq=equipped.reel===reel.id;
    const div=document.createElement("div"); div.className="upgrade-item";
    const controlStars="🎛️".repeat(reel.level);
    div.innerHTML=`<h4 style="color:${reel.color}">● ${reel.name} ${controlStars}</h4>
      <p style="font-size:11px;color:#888">${reel.desc}</p>`+
      (owned
        ? `<span class="owned-badge">${isEq?"✅ Equipped":"✔ Owned — equip in Gear"}</span>`
        : `<div class="cost-line">${reel.price} 🪙</div>
           <button class="btn btn-coin upg-btn" onclick="buyReel('${reel.id}')">Buy</button>`);
    reelSection.appendChild(div);
  });
  c.appendChild(reelSection);

  // Bait shop
  const baitSection=document.createElement("div"); baitSection.className="shop-section";
  baitSection.innerHTML="<h3>🪱 BAIT</h3>";
  BAIT_DB.forEach(bait=>{
    const qty=S.baitInv[bait.id]||0;
    const div=document.createElement("div"); div.className="cosmetic-item";
    div.innerHTML=`
      <h4>${bait.icon} ${bait.name} ${qty>0?`<span style="color:#5cb85c;font-size:11px">×${qty} owned</span>`:""}</h4>
      <p style="font-size:11px;color:#888;margin-bottom:5px">${bait.desc}</p>
      <div class="cost-line">${bait.price} 🪙 per pack (×${bait.stackSize})</div>
      <button class="btn btn-coin upg-btn" onclick="buyBait('${bait.id}')">Buy Pack</button>
    `;
    baitSection.appendChild(div);
  });
  c.appendChild(baitSection);
  const catDefs = [
    { key:"hats",    label:"👒 HATS",    icon: h => h.symbol||"👒", name: h => h.name },
    { key:"outfits", label:"👕 OUTFITS", icon: o => `<span style="color:${o.color}">■</span>`, name: o => o.name },
    { key:"bobbers", label:"🔴 BOBBERS", icon: b => `<span style="color:${b.topColor}">●</span>`, name: b => b.name },
    { key:"stools",  label:"🪑 STOOLS",  icon: s => `<span style="color:${s.color}">■</span>`, name: s => s.name },
  ];

  catDefs.forEach(({key,label,icon,name})=>{
    const unpurchased = COSMETICS[key].filter(i=>i.price>0&&!i.owned);
    if(!unpurchased.length) return; // hide category if everything is bought
    const sec=document.createElement("div"); sec.className="shop-section";
    sec.innerHTML=`<h3>${label}</h3>`;
    unpurchased.forEach(item=>{
      const div=document.createElement("div"); div.className="cosmetic-item";
      div.innerHTML=`<h4>${icon(item)} ${name(item)}</h4>
        <div class="cost-line">${item.price} 🪙</div>
        <button class="btn btn-coin upg-btn" onclick="buyCosmetic('${key}','${item.id}')">Buy</button>`;
      sec.appendChild(div);
    });
    c.appendChild(sec);
  });

  // If all cosmetics purchased
  const allBought = ["hats","outfits","bobbers","stools"].every(k=>COSMETICS[k].every(i=>i.owned));
  if(allBought){
    const div=document.createElement("div");
    div.style.cssText="color:#5cb85c;font-weight:800;font-size:13px;text-align:center;padding:10px 0";
    div.textContent="✨ You own everything! Check your Gear panel.";
    c.appendChild(div);
  }
}

