// ── EQUIPMENT GRID SLOT LABELS ────────────────────────────────
function updateEquipGrid(){
  const slotData = {
    hat:    { filled: equipped.hat!=="none",       name: ()=>{ const h=COSMETICS.hats.find(x=>x.id===equipped.hat); return h&&h.price>0?h.name:""; } },
    outfit: { filled: equipped.outfit!=="blue",    name: ()=>{ const o=COSMETICS.outfits.find(x=>x.id===equipped.outfit); return o&&o.price>0?o.name:""; } },
    bobber: { filled: equipped.bobber!=="classic", name: ()=>{ const b=COSMETICS.bobbers.find(x=>x.id===equipped.bobber); return b&&b.price>0?b.name:""; } },
    stool:  { filled: equipped.stool!=="wood",     name: ()=>{ const s=COSMETICS.stools.find(x=>x.id===equipped.stool); return s&&s.price>0?s.name:""; } },
    bait:   { filled: equipped.bait!=="none",      name: ()=>{ const b=BAIT_DB.find(x=>x.id===equipped.bait); return b?`×${S.baitInv[b.id]||0}`:""; } },
    rod:    { filled: equipped.rod!=="basic",   name: ()=>{ const r=ROD_DB.find(x=>x.id===equipped.rod);   return r?r.name:"Basic Rod";  } },
    reel:   { filled: equipped.reel!=="basic",  name: ()=>{ const r=REEL_DB.find(x=>x.id===equipped.reel); return r?r.name:"Basic Reel"; } },
  };

  Object.entries(slotData).forEach(([key,{filled,name}])=>{
    const slot   = document.getElementById(`eslot-${key}`);
    const nameEl = document.getElementById(`esname-${key}`);
    if(!slot||!nameEl) return;
    slot.classList.toggle("filled", filled);
    nameEl.textContent = filled ? name() : "";
  });

  // Update bait icon dynamically
  const baitIconEl = document.querySelector("#eslot-bait .es-icon");
  if(baitIconEl){
    if(equipped.bait !== "none"){
      const b = BAIT_DB.find(x=>x.id===equipped.bait);
      baitIconEl.textContent = b ? b.icon : "🪱";
    } else {
      baitIconEl.textContent = "🪱";
    }
  }
}


