let currentCharacter = "boy"; // "boy" | "girl"

const CHAR_IMGS = {};
(function(){
  ["boy","girl"].forEach(id => {
    const src = id === "boy"
      ? "data:image/png;base64,"
      : "data:image/png;base64,";
    const img = new Image();
    img.src = src;
    img.onload = () => { CHAR_IMGS[id] = img; drawCharPreview(); };
    CHAR_IMGS[id] = img;
  });
})();

function setCharacter(id){
  currentCharacter = id;
  document.getElementById("char-btn-boy") .classList.toggle("active", id==="boy");
  document.getElementById("char-btn-girl").classList.toggle("active", id==="girl");
  drawCharPreview();
}

// Chroma-key: removes green background, returns {canvas, data}
function chromaKey(img, threshold){
  threshold = threshold || 80;
  const offscreen = document.createElement("canvas");
  offscreen.width  = img.naturalWidth  || img.width;
  offscreen.height = img.naturalHeight || img.height;
  const oc = offscreen.getContext("2d");
  oc.drawImage(img, 0, 0);
  const data = oc.getImageData(0, 0, offscreen.width, offscreen.height);
  const d = data.data;
  for(let i = 0; i < d.length; i += 4){
    const r = d[i], g = d[i+1], b = d[i+2];
    if(g > 100 && g > r * 1.4 && g > b * 1.4){
      d[i+3] = 0;
    }
  }
  oc.putImageData(data, 0, 0);
  return { canvas: offscreen, data: data };
}

// Scan alpha to find tight bounding box of visible pixels
function visibleBounds(cr){
  const iw = cr.canvas.width, ih = cr.canvas.height, d = cr.data.data;
  let x0 = iw, x1 = 0, y0 = ih, y1 = 0;
  for(let y = 0; y < ih; y++){
    for(let x = 0; x < iw; x++){
      if(d[(y * iw + x) * 4 + 3] > 10){
        if(x < x0) x0 = x;
        if(x > x1) x1 = x;
        if(y < y0) y0 = y;
        if(y > y1) y1 = y;
      }
    }
  }
  if(x1 < x0) return { x:0, y:0, w:iw, h:ih }; // fallback
  return { x: x0, y: y0, w: x1 - x0 + 1, h: y1 - y0 + 1 };
}

// ── CHARACTER PREVIEW CANVAS ──────────────────────────────────
function drawCharPreview(){
  const canvas = document.getElementById("char-preview-canvas");
  if(!canvas) return;
  const c = canvas.getContext("2d");
  // Sync canvas buffer to CSS-rendered size (handles landscape resize via media query)
  const cssW = canvas.offsetWidth  || canvas.width;
  const cssH = canvas.offsetHeight || canvas.height;
  if(canvas.width !== cssW || canvas.height !== cssH){
    canvas.width  = cssW;
    canvas.height = cssH;
  }
  const W = canvas.width, H = canvas.height;
  c.clearRect(0,0,W,H);

  // ── Background hint ──
  c.fillStyle = "rgba(74,155,190,0.18)";
  c.fillRect(0, H*0.78, W, H*0.22);
  c.fillStyle = "rgba(138,188,74,0.28)";
  c.fillRect(0, H*0.74, W, H*0.06);

  const img = CHAR_IMGS[currentCharacter];
  if(img && img.complete && img.naturalWidth){
    // 1. Remove green background
    const keyed = chromaKey(img);
    // 2. Find tight pixel bounds — crop out all empty green margin
    const b = visibleBounds(keyed);
    // 3. Scale the CROPPED character to fill 95% of canvas height
    //    Only clamp by width to prevent literal overflow
    const scaleByH = (H * 0.95) / b.h;
    const scaleByW = W / b.w;
    const scale = Math.min(scaleByH, scaleByW);
    const dw = b.w * scale;
    const dh = b.h * scale;
    const dx = (W - dw) / 2;  // centered horizontally
    const dy = H - dh - 2;    // feet 2px from bottom
    // Source: only the tight character crop — no empty margins
    c.drawImage(keyed.canvas, b.x, b.y, b.w, b.h, dx, dy, dw, dh);
  } else {
    // Fallback silhouette while image loads
    c.fillStyle = "rgba(0,0,0,0.12)";
    c.beginPath(); c.arc(W/2, H*0.38, 18, 0, Math.PI*2); c.fill();
    c.fillRect(W/2-14, H*0.5, 28, 32);
  }
}

function renderWardrobe(){
  const wc=document.getElementById("wardrobe-content");
  wc.innerHTML="";

  const catDefs=[
    { key:"hats",    label:"👒 HATS",    slotKey:"hat",
      items: COSMETICS.hats.filter(h=>h.owned),
      icon: h=>h.symbol||"👒", name: h=>h.name },
    { key:"outfits", label:"👕 OUTFITS", slotKey:"outfit",
      items: COSMETICS.outfits.filter(o=>o.owned),
      icon: o=>`<span style="color:${o.color};font-size:20px">■</span>`, name: o=>o.name },
    { key:"bobbers", label:"🔴 BOBBERS", slotKey:"bobber",
      items: COSMETICS.bobbers.filter(b=>b.owned),
      icon: b=>`<span style="color:${b.topColor}">●</span><span style="color:${b.botColor}">●</span>`, name: b=>b.name },
    { key:"stools",  label:"🪑 STOOLS",  slotKey:"stool",
      items: COSMETICS.stools.filter(s=>s.owned),
      icon: s=>`<span style="color:${s.color};font-size:20px">■</span>`, name: s=>s.name },
  ];

  catDefs.forEach(({key,label,slotKey,items,icon,name})=>{
    if(!items.length) return;
    const sec=document.createElement("div"); sec.className="wardrobe-section";
    sec.innerHTML=`<h3>${label}</h3>`;
    const grid=document.createElement("div"); grid.className="wardrobe-grid";
    items.forEach(item=>{
      const isEq=equipped[slotKey]===item.id;
      const btn=document.createElement("div");
      btn.className="wardrobe-item"+(isEq?" active":"");
      btn.innerHTML=`<span class="wi-icon">${icon(item)}</span><span class="wi-name">${name(item)}</span>`;
      btn.onclick=()=>equipFromWardrobe(slotKey,item.id);
      grid.appendChild(btn);
    });
    sec.appendChild(grid);
    wc.appendChild(sec);
  });

  // Rod section
  if(S.ownedRods.length>1 || (S.ownedRods.length===1 && S.ownedRods[0]!=="basic")){
    const rsec=document.createElement("div"); rsec.className="wardrobe-section";
    rsec.innerHTML="<h3>🎣 RODS</h3>";
    const rgrid=document.createElement("div"); rgrid.className="wardrobe-grid";
    ROD_DB.filter(r=>S.ownedRods.includes(r.id)).forEach(rod=>{
      const isEq=equipped.rod===rod.id;
      const btn=document.createElement("div");
      btn.className="wardrobe-item"+(isEq?" active":"");
      btn.innerHTML=`<span class="wi-icon" style="color:${rod.color}">🎣</span><span class="wi-name">${rod.name}</span>`;
      btn.onclick=()=>{ equipped.rod=rod.id; applyStats(); updateStatsDisplay(); renderCharPanel(); saveGame(); showStatus(`🎣 ${rod.name} equipped!`,1000); };
      rgrid.appendChild(btn);
    });
    rsec.appendChild(rgrid);
    wc.appendChild(rsec);
  }

  // Reel section
  if(S.ownedReels.length>1 || (S.ownedReels.length===1 && S.ownedReels[0]!=="basic")){
    const rlsec=document.createElement("div"); rlsec.className="wardrobe-section";
    rlsec.innerHTML="<h3>🌀 REELS</h3>";
    const rlgrid=document.createElement("div"); rlgrid.className="wardrobe-grid";
    REEL_DB.filter(r=>S.ownedReels.includes(r.id)).forEach(reel=>{
      const isEq=equipped.reel===reel.id;
      const btn=document.createElement("div");
      btn.className="wardrobe-item"+(isEq?" active":"");
      btn.innerHTML=`<span class="wi-icon" style="color:${reel.color}">🌀</span><span class="wi-name">${reel.name}</span>`;
      btn.onclick=()=>{ equipped.reel=reel.id; applyStats(); updateStatsDisplay(); renderCharPanel(); saveGame(); showStatus(`🌀 ${reel.name} equipped!`,1000); };
      rlgrid.appendChild(btn);
    });
    rlsec.appendChild(rlgrid);
    wc.appendChild(rlsec);
  }

  // Bait section
  const ownedBait=BAIT_DB.filter(b=>(S.baitInv[b.id]||0)>0);
  if(ownedBait.length){
    const bsec=document.createElement("div"); bsec.className="wardrobe-section";
    bsec.innerHTML="<h3>🪱 BAIT</h3>";
    const bgrid=document.createElement("div"); bgrid.className="wardrobe-grid";
    ownedBait.forEach(bait=>{
      const isEq=equipped.bait===bait.id;
      const btn=document.createElement("div");
      btn.className="wardrobe-item"+(isEq?" active":"");
      btn.innerHTML=`<span class="wi-icon">${bait.icon}</span><span class="wi-name">${bait.name}<br>×${S.baitInv[bait.id]}</span>`;
      btn.onclick=()=>{
        equipped.bait=bait.id;
        updateBaitDisplay();
        renderCharPanel();
        saveGame();
        showStatus(`${bait.icon} ${bait.name} equipped — ${bait.hint}`,2000);
      };
      bgrid.appendChild(btn);
    });
    bsec.appendChild(bgrid);
    wc.appendChild(bsec);
  }

  if(wc.innerHTML===""){
    wc.innerHTML=`<div style="color:#aaa;font-size:13px;padding:6px 0">Nothing owned yet — visit the Shop!</div>`;
  }
}

function eslotClick(slotKey){
  // Scroll wardrobe to the relevant section
  const sectionMap={hat:"👒 HATS",outfit:"👕 OUTFITS",bobber:"🔴 BOBBERS",stool:"🪑 STOOLS",bait:"🪱 BAIT",rod:"🎣 RODS",reel:"🌀 REELS"};
  const label=sectionMap[slotKey];
  if(!label) return;
  const panel=document.getElementById("char-panel");
  const headers=panel.querySelectorAll(".wardrobe-section h3");
  headers.forEach(h=>{ if(h.textContent===label) h.scrollIntoView({behavior:"smooth",block:"nearest"}); });
}

function equipFromWardrobe(slotKey, id){
  equipped[slotKey]=id;
  tone(660,"sine",.12,.18);
  applyStats();
  updateStatsDisplay();
  renderCharPanel();
  saveGame();
  showStatus("✨ Equipped!",1000);
}

function unequipSlot(slotKey){
  const defaults={hat:"none",outfit:"blue",bobber:"classic",stool:"wood",bait:"none",rod:"basic",reel:"basic"};
  equipped[slotKey]=defaults[slotKey];
  if(slotKey==="bait") updateBaitDisplay();
  applyStats();
  updateStatsDisplay();
  renderCharPanel();
  saveGame();
}

function buyUpg(id){
  const u=UPGRADES.find(x=>x.id===id), lv=S.upgradeLevels[id];
  if(lv>=u.levels.length)return;
  const cost=u.levels[lv].cost;
  if(S.coins<cost){showStatus("Not enough coins! 🪙",1500);return;}
  S.coins-=cost; S.upgradeLevels[id]++; u.apply(S.upgradeLevels[id]);
  applyStats(); updateStatsDisplay();
  coinDisplay(); renderShop();
  // Redraw character preview if gear panel is open
  if(document.getElementById("char-panel").classList.contains("active")) drawCharPreview();
  saveGame();
  // Flash the screen briefly to celebrate the visual upgrade
  const pulse=document.getElementById("screen-pulse");
  pulse.style.borderColor="rgba(92,184,92,0.7)";
  pulse.classList.add("flash");
  setTimeout(()=>{ pulse.classList.remove("flash"); pulse.style.borderColor=""; },350);
  showStatus(`✅ ${u.name} upgraded — check your rod!`,2000);
}

function buyRod(id){
  const rod=ROD_DB.find(r=>r.id===id);
  if(!rod||S.ownedRods.includes(id))return;
  if(S.coins<rod.price){showStatus("Not enough coins! 🪙",1500);return;}
  S.coins-=rod.price;
  S.ownedRods.push(id);
  equipped.rod=id; // auto-equip on purchase
  applyStats(); updateStatsDisplay();
  coinDisplay(); renderShop();
  if(document.getElementById("char-panel").classList.contains("active")) renderCharPanel();
  saveGame();
  // Green flash
  const pulse=document.getElementById("screen-pulse");
  pulse.style.borderColor="rgba(92,184,92,0.7)";
  pulse.classList.add("flash");
  setTimeout(()=>{pulse.classList.remove("flash");pulse.style.borderColor="";},350);
  showStatus(`🎣 ${rod.name} equipped! Check your character.`,2000);
}

function buyReel(id){
  const reel=REEL_DB.find(r=>r.id===id);
  if(!reel||S.ownedReels.includes(id))return;
  if(S.coins<reel.price){showStatus("Not enough coins! 🪙",1500);return;}
  S.coins-=reel.price;
  S.ownedReels.push(id);
  equipped.reel=id; // auto-equip on purchase
  applyStats(); updateStatsDisplay();
  coinDisplay(); renderShop();
  if(document.getElementById("char-panel").classList.contains("active")) renderCharPanel();
  saveGame();
  const pulse=document.getElementById("screen-pulse");
  pulse.style.borderColor="rgba(92,184,92,0.7)";
  pulse.classList.add("flash");
  setTimeout(()=>{pulse.classList.remove("flash");pulse.style.borderColor="";},350);
  showStatus(`🌀 ${reel.name} equipped! Check your character.`,2000);
}

function buyCosmetic(category,id){
  const item=COSMETICS[category].find(x=>x.id===id);
  if(!item||item.owned)return;
  if(S.coins<item.price){showStatus("Not enough coins! 🪙",1500);return;}
  S.coins-=item.price; item.owned=true;
  coinDisplay(); renderShop();
  saveGame();
  showStatus(`🎉 Got ${item.name}! Equip it in the Gear panel.`,2000);
}

function buyBait(id){
  const bait=BAIT_DB.find(b=>b.id===id);
  if(!bait)return;
  if(S.coins<bait.price){showStatus("Not enough coins! 🪙",1500);return;}
  S.coins-=bait.price;
  S.baitInv[id]=(S.baitInv[id]||0)+bait.stackSize;
  coinDisplay(); renderShop();
  saveGame();
  showStatus(`${bait.icon} Got ${bait.stackSize}× ${bait.name}! Equip in Gear panel.`,2000);
}

function equipItem(type,id){
  // Legacy wrapper — used by old code paths
  equipped[type]=id;
  renderCharPanel();
  saveGame();
}

